36	TileShape get_cta_shape_for_config(CutlassTileConfig tile_config)
37	{
38	    switch (tile_config) {
39	        case CutlassTileConfig::CtaShape32x128x64_WarpShape32x32x64:
40	            return TileShape{32, 128};
41	        case CutlassTileConfig::CtaShape64x128x64_WarpShape32x64x64:
42	        case CutlassTileConfig::CtaShape64x128x64_WarpShape64x32x64:
