53	bool is_valid_split_k_factor(const int64_t   m,
54	                             const int64_t   n,
55	                             const int64_t   k,
56	                             const TileShape tile_shape,
57	                             const int       split_k_factor,
58	                             const size_t    workspace_bytes,
59	                             const bool      is_weight_only)
60	{
61	
62	    // All tile sizes have a k_tile of 64.
63	    static constexpr int k_tile = 64;
64	
65	    // For weight-only quant, we need k and k_elements_per_split to be a multiple of cta_k
66	    if (is_weight_only) {
67	        if ((k % k_tile) != 0) {
68	            return false;
69	        }
70	
71	        if ((k % split_k_factor) != 0) {
72	            return false;
73	        }
74	
75	        const int k_elements_per_split = k / split_k_factor;
76	        if ((k_elements_per_split % k_tile) != 0) {
77	            return false;
78	        }
79	    }
80	
81	    // Check that the workspace has sufficient space for this split-k factor
82	    const int ctas_in_m_dim     = (m + tile_shape.m - 1) / tile_shape.m;
83	    const int ctas_in_n_dim     = (n + tile_shape.n - 1) / tile_shape.n;
84	    const int required_ws_bytes = split_k_factor == 1 ? 0 : sizeof(int) * ctas_in_m_dim * ctas_in_n_dim;
85	
86	    if (required_ws_bytes > workspace_bytes) {
87	        return false;
88	    }
89	
90	    return true;
91	}
