99	                                                  CutlassTileConfig::CtaShape64x128x64_WarpShape32x64x64,
100	                                                  CutlassTileConfig::CtaShape128x128x64_WarpShape64x32x64};
101	
102	    std::vector<CutlassTileConfig> quant_B_configs{CutlassTileConfig::CtaShape32x128x64_WarpShape32x32x64,
103	                                                   CutlassTileConfig::CtaShape64x128x64_WarpShape64x32x64,
104	                                                   CutlassTileConfig::CtaShape128x128x64_WarpShape128x32x64};
105	
106	    const std::vector<CutlassTileConfig> allowed_configs = is_weight_only ? quant_B_configs : square_configs;
107	    return simt_configs_only ? simt_configs : allowed_configs;
