113	
114	    std::vector<CutlassGemmConfig> candidate_configs;
115	    const int                      min_stages = 2;
116	    const int                      max_stages = sm >= 80 ? 4 : 2;
117	
118	    for (const auto& tile_config : tiles) {
119	        for (int stages = min_stages; stages <= max_stages; ++stages) {
120	            CutlassGemmConfig config{tile_config, SplitKStyle::NO_SPLIT_K, 1, stages};
121	            candidate_configs.push_back(config);
122	        }
123	    }
124	
125	    return candidate_configs;
126	}
