128	CutlassGemmConfig estimate_best_config_from_occupancies(const std::vector<CutlassGemmConfig>& candidate_configs,
129	                                                        const std::vector<int>&               occupancies,
130	                                                        const int64_t                         m,
131	                                                        const int64_t                         n,
132	                                                        const int64_t                         k,
133	                                                        const int64_t                         num_experts,
134	                                                        const int                             split_k_limit,
135	                                                        const size_t                          workspace_bytes,
136	                                                        const int                             multi_processor_count,
137	                                                        const int                             is_weight_only)
138	{
139	
140	    if (occupancies.size() != candidate_configs.size()) {
141	        throw std::runtime_error("[FT Error][estimate_best_config_from_occupancies] occpancies and "
142	                                 "candidate configs vectors must have equal length.");
143	    }
144	
145	    CutlassGemmConfig best_config;
146	    // Score will be [0, 1]. The objective is to minimize this score.
147	    // It represents the fraction of SM resources unused in the last wave.
148	    float config_score   = 1.0f;
149	    int   config_waves   = INT_MAX;
150	    int   current_m_tile = 0;
151	
152	    const int max_split_k = n >= multi_processor_count * 256 ? 1 : split_k_limit;
153	    for (int ii = 0; ii < candidate_configs.size(); ++ii) {
154	        CutlassGemmConfig candidate_config = candidate_configs[ii];
155	        TileShape         tile_shape       = get_cta_shape_for_config(candidate_config.tile_config);
156	        int               occupancy        = occupancies[ii];
157	
158	        if (occupancy == 0) {
159	            continue;
160	        }
161	
162	        // Keep small tile sizes when possible.
163	        if (best_config.tile_config != CutlassTileConfig::ChooseWithHeuristic && m < current_m_tile
164	            && current_m_tile < tile_shape.m) {
165	            continue;
166	        }
167	
168	        const int ctas_in_m_dim = (m + tile_shape.m - 1) / tile_shape.m;
169	        const int ctas_in_n_dim = (n + tile_shape.n - 1) / tile_shape.n;
170	
171	        for (int split_k_factor = 1; split_k_factor <= max_split_k; ++split_k_factor) {
172	            if (is_valid_split_k_factor(m, n, k, tile_shape, split_k_factor, workspace_bytes, is_weight_only)) {
173	                const int ctas_per_wave    = occupancy * multi_processor_count;
174	                const int ctas_for_problem = ctas_in_m_dim * ctas_in_n_dim * split_k_factor;
175	
176	                const int   num_waves_total      = (ctas_for_problem + ctas_per_wave - 1) / ctas_per_wave;
177	                const float num_waves_fractional = ctas_for_problem / float(ctas_per_wave);
178	                const float current_score        = float(num_waves_total) - num_waves_fractional;
179	
180	                const float score_slack = 0.1f;
181	                if (current_score < config_score
182	                    || ((config_waves > num_waves_total) && (current_score < config_score + score_slack))) {
183	                    config_score = current_score;
184	                    config_waves = num_waves_total;
185	                    SplitKStyle split_style =
186	                        split_k_factor > 1 ? SplitKStyle::SPLIT_K_SERIAL : SplitKStyle::NO_SPLIT_K;
187	                    best_config = CutlassGemmConfig{
188	                        candidate_config.tile_config, split_style, split_k_factor, candidate_config.stages};
189	                    current_m_tile = tile_shape.m;
190	                }
191	                else if (current_score == config_score
192	                         && (best_config.stages < candidate_config.stages || split_k_factor < best_config.split_k_factor
193	                             || current_m_tile < tile_shape.m)) {
194	                    // Prefer deeper pipeline or smaller split-k
195	                    SplitKStyle split_style =
196	                        split_k_factor > 1 ? SplitKStyle::SPLIT_K_SERIAL : SplitKStyle::NO_SPLIT_K;
197	                    best_config = CutlassGemmConfig{
198	                        candidate_config.tile_config, split_style, split_k_factor, candidate_config.stages};
199	                    current_m_tile = tile_shape.m;
200	                    config_waves   = num_waves_total;
201	                }
202	            }
203	        }
204	    }
205	
206	    if (best_config.tile_config == CutlassTileConfig::ChooseWithHeuristic) {
207	        throw std::runtime_error("[FT Error] Heurisitc failed to find a valid config.");
208	    }
209	
210	    return best_config;
211	}
