113	{
114	    auto _st = row_major_quantized_weight.scalar_type();
115	    CHECK_CPU(row_major_quantized_weight);
116	    CHECK_CONTIGUOUS(row_major_quantized_weight);
117	    TORCH_CHECK(_st == torch::kInt8, "Quantized tensor must be int8 dtype");
118	    check_quant_type_allowed(quant_type);
119	    TORCH_CHECK(row_major_quantized_weight.dim() == 2 || row_major_quantized_weight.dim() == 3,
120	                "Invalid dim. The dim of weight should be 2 or 3");
121	
122	    ft::QuantType ft_quant_type      = get_ft_quant_type(quant_type);
123	    const size_t  bits_in_quant_type = get_bits_in_quant_type(ft_quant_type);
124	
125	    const size_t num_experts = row_major_quantized_weight.dim() == 2 ? 1 : row_major_quantized_weight.size(0);
126	    const size_t num_rows    = row_major_quantized_weight.size(-2);
127	    const size_t num_cols    = (8 / bits_in_quant_type) * row_major_quantized_weight.size(-1);
128	
129	    Tensor  processed_tensor = torch::zeros_like(row_major_quantized_weight);
130	    int8_t* input_byte_ptr   = get_ptr<int8_t>(row_major_quantized_weight);
131	    int8_t* output_byte_ptr  = get_ptr<int8_t>(processed_tensor);
132	
133	    ft::preprocess_weights_for_mixed_gemm(
134	        output_byte_ptr, input_byte_ptr, {num_experts, num_rows, num_cols}, ft_quant_type);
135	
136	    return processed_tensor;
137	}
